import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import { StatusBadge, PriorityBadge, formatDate } from '../utils/statusHelpers';
import Sidebar from '../components/common/Sidebar';
import { DatePicker } from '../components/common/DatePicker';

const BOARD_COLUMNS = [
  { key: 'overdue',              label: 'Overdue',          color: 'var(--red)' },
  { key: 'approved',             label: 'Approved',         color: 'var(--green)' },
  { key: 'prioritized',          label: 'Prioritized',      color: 'var(--accent)' },
  { key: 'planned',              label: 'Planned',          color: 'var(--cyan)' },
  { key: 'assigned',             label: 'Assigned',         color: 'var(--purple)' },
  { key: 'in_progress',          label: 'In Progress',      color: 'var(--blue)' },
  { key: 'printed',              label: 'Printed',          color: 'var(--green)' },
  { key: 'quality_check',        label: 'Quality Check',    color: 'var(--yellow)' },
  { key: 'ready_for_pickup',     label: 'Completed Awaiting Confirmation', color: 'var(--green)' },
  { key: 'blocked',              label: 'Blocked',          color: 'var(--red)' },
  { key: 'on_hold',              label: 'On Hold',          color: 'var(--yellow)' },
];

const PriorityDot = ({ priority }) => {
  const colors = { critical: '#ef4444', high: '#f59e0b', normal: '#3b82f6', low: '#64748b' };
  return (
    <span style={{
      width: 8, height: 8, borderRadius: '50%', display: 'inline-block',
      background: colors[priority] || '#64748b', flexShrink: 0,
    }}/>
  );
};

const RequestCard = ({ request, onClick }) => {
  const overdue = Boolean(request.is_overdue);
  const dueDate = request.approved_due_date || request.requested_due_date;
  return (
    <div
      onClick={() => onClick(request.id)}
      style={{
        background: 'var(--bg-secondary)',
        border: `1px solid ${overdue ? 'rgba(239,68,68,0.4)' : 'var(--border)'}`,
        borderRadius: 8,
        padding: '0.75rem',
        cursor: 'pointer',
        transition: 'var(--transition)',
        marginBottom: '0.5rem',
      }}
      onMouseEnter={e => e.currentTarget.style.borderColor = 'var(--border-light)'}
      onMouseLeave={e => e.currentTarget.style.borderColor = overdue ? 'rgba(239,68,68,0.4)' : 'var(--border)'}
    >
      <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', marginBottom: '0.35rem' }}>
        <PriorityDot priority={request.priority}/>
        <span style={{ fontSize: '0.7rem', color: 'var(--accent)', fontFamily: 'var(--font-mono)', fontWeight: 600 }}>
          {request.request_number}
        </span>
        {overdue && (
          <span style={{ marginLeft: 'auto', fontSize: '0.65rem', color: 'var(--red)', fontWeight: 700 }}>LATE</span>
        )}
      </div>
      <div style={{ fontSize: '0.82rem', fontWeight: 600, lineHeight: 1.3, marginBottom: '0.4rem', color: 'var(--text-primary)' }}>
        {request.title}
      </div>
      {request.technician_name && (
        <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginBottom: '0.25rem' }}>
          👤 {request.technician_name}
        </div>
      )}
      {request.printer_name && (
        <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginBottom: '0.25rem' }}>
          🖨 {request.printer_name}
        </div>
      )}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '0.4rem' }}>
        <span style={{ fontSize: '0.7rem', color: 'var(--text-muted)' }}>
          {request.requester_department}
        </span>
        {dueDate && (
          <span style={{ fontSize: '0.7rem', color: overdue ? 'var(--red)' : 'var(--text-muted)' }}>
            Due: {formatDate(dueDate)}
          </span>
        )}
      </div>
    </div>
  );
};

export default function PlanningBoardPage() {
  const navigate = useNavigate();
  const [board, setBoard] = useState({});
  const [boardSummary, setBoardSummary] = useState({});
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState('board'); // board | schedule | technician
  const [filters, setFilters] = useState({
    site_id: '', status: '', priority: '', technician_id: '',
    date_from: '', date_to: '', month: '', year: '', printer_id: '',
  });
  const [filterOptions, setFilterOptions] = useState({ sites: [], printers: [], technicians: [] });

  const query = new URLSearchParams(Object.entries(filters).filter(([, v]) => v)).toString();
  const setFilter = (key, value) => setFilters(prev => ({ ...prev, [key]: value }));

  const fetchBoard = useCallback(async () => {
    setLoading(true);
    try {
      const res = await api.get(`/planning/board${query ? `?${query}` : ''}`);
      setBoard(res.data.board || res.data);
      setBoardSummary(res.data.summary || {});
    } catch (err) { console.error(err); }
    setLoading(false);
  }, [query]);

  useEffect(() => { fetchBoard(); }, [fetchBoard]);
  useEffect(() => {
    Promise.all([api.get('/sites'), api.get('/printers'), api.get('/users')])
      .then(([sites, printers, users]) => {
        setFilterOptions({
          sites: sites.data,
          printers: printers.data,
          technicians: users.data.filter(u => u.role === 'technician'),
        });
      })
      .catch(err => console.error('[Planning] Filter options failed:', err));
  }, []);

  const totalCards = Object.values(board).reduce((s, col) => s + col.length, 0);

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>Planning Board</h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              {totalCards} active request{totalCards !== 1 ? 's' : ''} in workflow
            </p>
          </div>
          <div style={{ display: 'flex', gap: '0.5rem' }}>
            <button className={`btn btn-sm ${view === 'board' ? 'btn-primary' : 'btn-ghost'}`} onClick={() => setView('board')}>
              Board
            </button>
            <button className={`btn btn-sm ${view === 'schedule' ? 'btn-primary' : 'btn-ghost'}`} onClick={() => setView('schedule')}>
              Printer Schedule
            </button>
            <button className={`btn btn-sm ${view === 'technician' ? 'btn-primary' : 'btn-ghost'}`} onClick={() => setView('technician')}>
              Technician Schedule
            </button>
            <button className="btn btn-ghost btn-sm" onClick={fetchBoard}>↻ Refresh</button>
          </div>
        </div>

        {loading ? (
          <div style={{ display: 'flex', justifyContent: 'center', padding: '3rem' }}>
            <span className="spinner" style={{ width: 32, height: 32 }}/>
          </div>
        ) : view === 'board' ? (
          <div className="page-body">
            <PlanningFilterBar filters={filters} setFilter={setFilter} options={filterOptions}/>
            <KpiGrid items={[
              ['Total Requests', boardSummary.totalRequests || totalCards],
              ['Overdue Requests', boardSummary.overdueRequests || 0, 'var(--red)'],
              ['In Progress', boardSummary.inProgressRequests || 0, 'var(--blue)'],
              ['Blocked', boardSummary.blockedRequests || 0, 'var(--red)'],
              ['High Priority', boardSummary.highPriorityRequests || 0, 'var(--yellow)'],
              ['Planned', boardSummary.plannedRequests || 0, 'var(--cyan)'],
              ['Assigned', boardSummary.assignedRequests || 0, 'var(--purple)'],
              ['Quality Check', boardSummary.qualityCheckRequests || 0, 'var(--yellow)'],
            ]}/>
            <div style={{
              overflowX: 'auto',
              display: 'flex',
              gap: '0.75rem',
              minHeight: 'calc(100vh - 285px)',
              alignItems: 'flex-start',
            }}>
            {BOARD_COLUMNS.map(col => {
              const cards = board[col.key] || [];
              return (
                <div key={col.key} style={{
                  minWidth: 240, width: 240, flexShrink: 0,
                  background: 'var(--bg-card)',
                  border: '1px solid var(--border)',
                  borderRadius: 10,
                  borderTop: `3px solid ${col.color}`,
                  display: 'flex', flexDirection: 'column',
                  maxHeight: 'calc(100vh - 140px)',
                }}>
                  {/* Column header */}
                  <div style={{ padding: '0.75rem', borderBottom: '1px solid var(--border)', flexShrink: 0 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <span style={{ fontSize: '0.78rem', fontWeight: 700, color: 'var(--text-primary)', textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                        {col.label}
                      </span>
                      <span style={{
                        background: cards.length > 0 ? col.color + '22' : 'var(--bg-hover)',
                        color: cards.length > 0 ? col.color : 'var(--text-muted)',
                        borderRadius: '10px', padding: '0.1rem 0.5rem',
                        fontSize: '0.72rem', fontWeight: 700,
                      }}>
                        {cards.length}
                      </span>
                    </div>
                  </div>
                  {/* Cards */}
                  <div style={{ padding: '0.5rem', overflowY: 'auto', flex: 1 }}>
                    {cards.length === 0 ? (
                      <div style={{ textAlign: 'center', padding: '1.5rem 0.5rem', color: 'var(--text-muted)', fontSize: '0.75rem' }}>
                        Empty
                      </div>
                    ) : (
                      cards.map(r => (
                        <RequestCard key={r.id} request={r} onClick={(id) => navigate(`/requests/${id}`)}/>
                      ))
                    )}
                  </div>
                </div>
              );
            })}
            </div>
          </div>
        ) : view === 'schedule' ? (
          <PrinterScheduleView navigate={navigate} filters={filters} setFilter={setFilter} options={filterOptions} query={query}/>
        ) : (
          <TechnicianScheduleView navigate={navigate} filters={filters} setFilter={setFilter} options={filterOptions} query={query}/>
        )}
      </div>
    </div>
  );
}

function PrinterScheduleView({ navigate, filters, setFilter, options, query }) {
  const [schedule, setSchedule] = useState([]);
  const [summary, setSummary] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    api.get(`/planning/printer-schedule${query ? `?${query}` : ''}`)
      .then(r => {
        setSchedule(r.data.printers || r.data);
        setSummary(r.data.summary || {});
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, [query]);

  if (loading) return (
    <div style={{ display: 'flex', justifyContent: 'center', padding: '3rem' }}>
      <span className="spinner" style={{ width: 28, height: 28 }}/>
    </div>
  );

  return (
    <div className="page-body">
      <PlanningFilterBar filters={filters} setFilter={setFilter} options={options}/>
      <KpiGrid items={[
        ['Total Printers', summary.totalPrinters || schedule.length],
        ['Total Jobs', summary.totalJobs || 0],
        ['Active Jobs', summary.activeJobs || 0, 'var(--blue)'],
        ['Overdue Jobs', summary.overdueJobs || 0, 'var(--red)'],
        ['Blocked Jobs', summary.blockedJobs || 0, 'var(--red)'],
        ['High Priority', summary.highPriorityJobs || 0, 'var(--yellow)'],
        ['Estimated Hours', `${(summary.totalEstimatedHours || 0).toFixed?.(2) || summary.totalEstimatedHours || 0} h`],
        ['Actual Hours', `${(summary.totalActualHours || 0).toFixed?.(2) || summary.totalActualHours || 0} h`],
      ]}/>
      <div className="card" style={{ marginBottom: '1rem', display: 'flex', gap: '1.5rem', flexWrap: 'wrap', color: 'var(--text-secondary)', fontSize: '0.82rem' }}>
        <span>Most loaded printer: <strong style={{ color: 'var(--text-primary)' }}>{summary.mostLoadedPrinter || '—'}</strong></span>
        <span>Least loaded printer: <strong style={{ color: 'var(--text-primary)' }}>{summary.leastLoadedPrinter || '—'}</strong></span>
      </div>
      {schedule.length === 0 ? (
        <div className="empty-state"><p>No active printer jobs</p></div>
      ) : (
        schedule.map((printer, i) => (
          <div key={i} className="card" style={{ marginBottom: '1rem' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1rem' }}>
              <span style={{ fontSize: '1.2rem' }}>🖨</span>
              <div>
                <div style={{ fontWeight: 700, fontFamily: 'var(--font-heading)' }}>{printer.printer_name}</div>
                <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{printer.technology} · {printer.jobs.length} job{printer.jobs.length !== 1 ? 's' : ''}</div>
              </div>
            </div>
            <div className="table-container">
              <table>
                <thead>
                  <tr><th>ID</th><th>Title</th><th>Status</th><th>Priority</th><th>Technician</th><th>Start</th><th>Due</th></tr>
                </thead>
                <tbody>
                  {printer.jobs.map(j => (
                    <tr key={j.id} style={{ cursor: 'pointer' }} onClick={() => navigate(`/requests/${j.id}`)}>
                      <td style={{ fontFamily: 'var(--font-mono)', fontSize: '0.75rem', color: 'var(--accent)', fontWeight: 600 }}>{j.request_number}</td>
                      <td style={{ fontSize: '0.83rem' }}>{j.title}</td>
                      <td><StatusBadge status={j.status}/></td>
                      <td><PriorityBadge priority={j.priority}/></td>
                      <td style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>{j.technician_name || '—'}</td>
                      <td style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>{formatDate(j.planned_start_date)}</td>
                      <td style={{ fontSize: '0.78rem', color: 'var(--text-muted)' }}>{formatDate(j.approved_due_date)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        ))
      )}
    </div>
  );
}

const LOAD_CONFIG = {
  low: { label: 'Low Load', color: 'var(--green)', bg: 'var(--green-dim)' },
  medium: { label: 'Medium Load', color: 'var(--yellow)', bg: 'var(--yellow-dim)' },
  high: { label: 'High Load', color: 'var(--red)', bg: 'var(--red-dim)' },
};

const months = [
  ['1', 'January'], ['2', 'February'], ['3', 'March'], ['4', 'April'],
  ['5', 'May'], ['6', 'June'], ['7', 'July'], ['8', 'August'],
  ['9', 'September'], ['10', 'October'], ['11', 'November'], ['12', 'December'],
];

const years = Array.from({ length: 8 }, (_, i) => new Date().getFullYear() - i);

function KpiGrid({ items }) {
  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, minmax(0, 1fr))', gap: '1rem', marginBottom: '1rem' }}>
      {items.map(([label, value, color]) => (
        <div key={label} className="card" style={{ padding: '0.85rem' }}>
          <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.3rem' }}>{label}</div>
          <div style={{ fontSize: '1rem', fontWeight: 800, color: color || 'var(--text-primary)' }}>{value ?? 0}</div>
        </div>
      ))}
    </div>
  );
}

function PlanningFilterBar({ filters, setFilter, options, actions }) {
  const [open, setOpen] = useState(false);
  const [draft, setDraft] = useState(filters);

  const openDrawer = () => {
    setDraft(filters);
    setOpen(true);
  };

  const applyFilters = () => {
    ['priority', 'printer_id', 'date_from', 'date_to', 'month', 'year'].forEach(key => setFilter(key, draft[key] || ''));
    setOpen(false);
  };

  const resetFilters = () => {
    const reset = { priority: '', printer_id: '', date_from: '', date_to: '', month: '', year: '' };
    Object.entries(reset).forEach(([key, value]) => setFilter(key, value));
    setDraft(prev => ({ ...prev, ...reset }));
    setOpen(false);
  };

  return (
    <>
      <div className="card" style={{ marginBottom: '1rem', padding: '0.85rem 1rem' }}>
        <div className="planning-filter-toolbar">
          <div className="form-group"><label className="form-label">Site</label>
          <select className="form-select" value={filters.site_id} onChange={e => setFilter('site_id', e.target.value)}>
            <option value="">All sites</option>{options.sites.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
          </div>
          <div className="form-group"><label className="form-label">Status</label>
          <select className="form-select" value={filters.status} onChange={e => setFilter('status', e.target.value)}>
            <option value="">All statuses</option>
            {['approved','prioritized','planned','assigned','in_progress','printed','quality_check','ready_for_pickup','blocked','on_hold','rework_required'].map(s => <option key={s} value={s}>{s}</option>)}
          </select>
          </div>
          <div className="form-group"><label className="form-label">Technician</label>
          <select className="form-select" value={filters.technician_id} onChange={e => setFilter('technician_id', e.target.value)}>
            <option value="">All technicians</option>{options.technicians.map(t => <option key={t.id} value={t.id}>{t.first_name} {t.last_name}</option>)}
          </select>
          </div>
          <button className="btn btn-secondary btn-sm" onClick={openDrawer}>Filters ⚙</button>
          {actions}
        </div>
      </div>
      {open && (
        <div className="filter-drawer-overlay" onClick={() => setOpen(false)}>
          <aside className="filter-drawer" onClick={e => e.stopPropagation()}>
            <div className="filter-drawer-header">
              <div>
                <h3>Planning Filters</h3>
                <p>Secondary planning filters for priority, printer, and date.</p>
              </div>
              <button className="btn btn-ghost btn-sm" onClick={() => setOpen(false)}>Close</button>
            </div>
            <div className="filter-drawer-body">
              <div className="form-group"><label className="form-label">Priority</label>
                <select className="form-select" value={draft.priority || ''} onChange={e => setDraft(prev => ({ ...prev, priority: e.target.value }))}>
                  <option value="">All priorities</option>{['critical','high','normal','low'].map(p => <option key={p} value={p}>{p}</option>)}
                </select>
              </div>
              <div className="form-group"><label className="form-label">Printer</label>
                <select className="form-select" value={draft.printer_id || ''} onChange={e => setDraft(prev => ({ ...prev, printer_id: e.target.value }))}>
                  <option value="">All printers</option>{options.printers.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                </select>
              </div>
              <div className="form-group"><label className="form-label">Date Start</label><DatePicker value={draft.date_from || ''} onChange={v => setDraft(prev => ({ ...prev, date_from: v }))} placeholder="Start date"/></div>
              <div className="form-group"><label className="form-label">Date End</label><DatePicker value={draft.date_to || ''} onChange={v => setDraft(prev => ({ ...prev, date_to: v }))} placeholder="End date"/></div>
              <div className="form-group"><label className="form-label">Month</label>
                <select className="form-select" value={draft.month || ''} onChange={e => setDraft(prev => ({ ...prev, month: e.target.value }))}>
                  <option value="">All months</option>{months.map(([v, l]) => <option key={v} value={v}>{l}</option>)}
                </select>
              </div>
              <div className="form-group"><label className="form-label">Year</label>
                <select className="form-select" value={draft.year || ''} onChange={e => setDraft(prev => ({ ...prev, year: e.target.value }))}>
                  <option value="">All years</option>{years.map(y => <option key={y} value={y}>{y}</option>)}
                </select>
              </div>
            </div>
            <div className="filter-drawer-footer">
              <button className="btn btn-ghost" onClick={resetFilters}>Reset Filters</button>
              <button className="btn btn-primary" onClick={applyFilters}>Apply Filters</button>
            </div>
          </aside>
        </div>
      )}
    </>
  );
}

function TechnicianScheduleView({ navigate, filters, setFilter, options, query }) {
  const [data, setData] = useState({ summary: {}, technicians: [] });
  const [loading, setLoading] = useState(true);
  const [exporting, setExporting] = useState(false);

  const fetchSchedule = useCallback(() => {
    setLoading(true);
    api.get(`/planning/technician-schedule${query ? `?${query}` : ''}`)
      .then(r => setData(r.data))
      .catch(err => console.error('[Planning] Technician schedule failed:', err))
      .finally(() => setLoading(false));
  }, [query]);

  useEffect(() => { fetchSchedule(); }, [fetchSchedule]);

  const downloadExport = async () => {
    setExporting(true);
    try {
      const response = await api.get(`/export/technician-workload-report${query ? `?${query}` : ''}`, { responseType: 'blob' });
      const blob = new Blob([response.data], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', 'Technician Workload Report.xlsx');
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (err) {
      console.error('[Planning] Technician export failed:', err);
      alert('Technician workload export failed.');
    } finally {
      setExporting(false);
    }
  };

  if (loading) return (
    <div style={{ display: 'flex', justifyContent: 'center', padding: '3rem' }}>
      <span className="spinner" style={{ width: 28, height: 28 }}/>
    </div>
  );

  const summary = data.summary || {};

  return (
    <div className="page-body">
      <PlanningFilterBar
        filters={filters}
        setFilter={setFilter}
        options={options}
        actions={(
          <button className="btn btn-primary btn-sm" onClick={downloadExport} disabled={exporting}>
            {exporting ? <span className="spinner" style={{ width: 14, height: 14 }}/> : null}
            Export Excel
          </button>
        )}
      />

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, minmax(0, 1fr))', gap: '1rem', marginBottom: '1rem' }}>
        {[
          ['Total Technicians', summary.totalTechnicians || 0],
          ['Total Assigned Requests', summary.totalAssignedRequests || 0],
          ['Avg Requests / Technician', summary.averageRequestsPerTechnician || 0],
          ['Overdue Requests', summary.overdueRequests || 0],
          ['Most Loaded Technician', summary.mostLoadedTechnician || '—'],
          ['Least Loaded Technician', summary.leastLoadedTechnician || '—'],
          ['Total Estimated Hours', `${(summary.totalEstimatedHours || 0).toFixed?.(2) || summary.totalEstimatedHours || 0} h`],
          ['Total Actual Hours', `${(summary.totalActualHours || 0).toFixed?.(2) || summary.totalActualHours || 0} h`],
        ].map(([label, value]) => (
          <div key={label} className="card" style={{ padding: '0.85rem' }}>
            <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: '0.3rem' }}>{label}</div>
            <div style={{ fontSize: '1rem', fontWeight: 800 }}>{value}</div>
          </div>
        ))}
      </div>

      {data.technicians.map(tech => {
        const cfg = LOAD_CONFIG[tech.loadLevel] || LOAD_CONFIG.low;
        return (
          <div key={tech.technicianId} className="card" style={{ marginBottom: '1rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', gap: '1rem', alignItems: 'flex-start', marginBottom: '1rem' }}>
              <div>
                <div style={{ fontWeight: 800, fontFamily: 'var(--font-heading)' }}>{tech.technicianName}</div>
                <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginTop: '0.2rem' }}>
                  {tech.assignedRequests} assigned · {tech.openRequests} open · {tech.inProgressRequests} in progress · {tech.overdueRequests} overdue
                </div>
              </div>
              <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center', flexWrap: 'wrap', justifyContent: 'flex-end' }}>
                <span style={{ fontSize: '0.72rem', fontWeight: 700, padding: '0.2rem 0.6rem', borderRadius: 4, background: cfg.bg, color: cfg.color }}>{cfg.label}</span>
                <span style={{ fontSize: '0.78rem', color: 'var(--text-secondary)' }}>Est. {tech.estimatedHours.toFixed(2)}h</span>
                <span style={{ fontSize: '0.78rem', color: 'var(--text-secondary)' }}>Actual {tech.actualHours.toFixed(2)}h</span>
              </div>
            </div>
            {tech.requests.length === 0 ? (
              <div className="empty-state" style={{ padding: '1.5rem' }}><p>No assigned requests</p></div>
            ) : (
              <div className="table-container">
                <table>
                  <thead>
                    <tr><th>ID</th><th>Title</th><th>Status</th><th>Priority</th><th>Site</th><th>Due Date</th><th>Est. Time</th><th>Printer</th><th>Overdue</th></tr>
                  </thead>
                  <tbody>
                    {tech.requests.map(r => (
                      <tr key={r.id} style={{ cursor: 'pointer' }} onClick={() => navigate(`/requests/${r.id}`)}>
                        <td style={{ fontFamily: 'var(--font-mono)', color: 'var(--accent)', fontWeight: 700 }}>{r.request_number}</td>
                        <td>{r.title}</td>
                        <td><StatusBadge status={r.status}/></td>
                        <td><PriorityBadge priority={r.priority}/></td>
                        <td>{r.site_name || '—'}</td>
                        <td style={{ color: r.is_overdue ? 'var(--red)' : 'var(--text-secondary)' }}>{formatDate(r.due_date)}</td>
                        <td>{r.estimated_printing_time ? `${r.estimated_printing_time} min` : '—'}</td>
                        <td>{r.printer_name || '—'}</td>
                        <td>{r.is_overdue ? <span style={{ color: 'var(--red)', fontWeight: 800 }}>Overdue</span> : '—'}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}
